module top_module(shift_Z, X, S, LEFT, LOG);input signed [31:0]  X;
   input [4:0]   S;
   input         LEFT;
   input         LOG;
   output reg signed [31:0] shift_Z;

   always @(*) begin
      case ({LEFT, LOG})
        2'b00 : shift_Z <= X >>> S;
        2'b01 : shift_Z <= X >> S;
        2'b10 : shift_Z <= X <<< S;
        2'b11 : shift_Z <= X << S;
      endcase
   end

endmodule
